    <title>Todo List</title>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&display=swap" rel="stylesheet">
    <style>
        :root {
            --primary-color: #4CAF50;
            --secondary-color: #f4f4f4;
            --text-color: #333;
            --spacing: 16px;
        }

        body {
            font-family: 'Inter', sans-serif;
            margin: 0;
            padding: 0;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            background-color: var(--secondary-color);
        }

        .container {
            max-width: 400px;
            width: 100%;
            background: white;
            padding: var(--spacing);
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
            border-radius: 8px;
        }

        h1 {
            font-size: 24px;
            margin-bottom: var(--spacing);
            color: var(--primary-color);
        }

        .task-input {
            display: flex;
            gap: var(--spacing);
            margin-bottom: var(--spacing);
        }

        .task-input input {
            flex: 1;
            padding: var(--spacing);
            border: 1px solid #ddd;
            border-radius: 4px;
            font-size: 16px;
        }

        .task-input button {
            padding: var(--spacing);
            background-color: var(--primary-color);
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            transition: background-color 0.3s ease;
        }

        .task-input button:hover {
            background-color: #45a049;
        }

        .tasks {
            list-style: none;
            padding: 0;
            margin: 0;
        }

        .task {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: var(--spacing);
            border-bottom: 1px solid #ddd;
        }

        .task:last-child {
            border-bottom: none;
        }

        .task.completed .task-text {
            text-decoration: line-through;
            opacity: 0.6;
        }

        .task button {
            background: none;
            border: none;
            color: #888;
            cursor: pointer;
            transition: color 0.3s ease;
        }

        .task button:hover {
            color: #555;
        }

        .empty-state {
            text-align: center;
            color: #888;
            margin-top: var(--spacing);
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Todo List</h1>
        <div class="task-input">
            <input type="text" id="taskInput" placeholder="Add a new task">
            <button id="addTaskButton">Add</button>
        </div>
        <ul class="tasks" id="taskList"></ul>
        <div class="empty-state" id="emptyState">No tasks yet!</div>
    </div>

    <script>
        const taskInput = document.getElementById('taskInput');
        const addTaskButton = document.getElementById('addTaskButton');
        const taskList = document.getElementById('taskList');
        const emptyState = document.getElementById('emptyState');

        let tasks = JSON.parse(localStorage.getItem('tasks')) || [];

        function renderTasks() {
            taskList.innerHTML = '';
            tasks.forEach((task, index) => {
                const taskItem = document.createElement('li');
                taskItem.className = `task ${task.completed ? 'completed' : ''}`;

                const taskText = document.createElement('span');
                taskText.className = 'task-text';
                taskText.textContent = task.text;
                taskText.addEventListener('click', () => toggleTaskCompletion(index));

                const deleteButton = document.createElement('button');
                deleteButton.textContent = 'Delete';
                deleteButton.addEventListener('click', () => deleteTask(index));

                taskItem.appendChild(taskText);
                taskItem.appendChild(deleteButton);
                taskList.appendChild(taskItem);
            });

            emptyState.style.display = tasks.length ? 'none' : 'block';
        }

        function addTask() {
            const taskText = taskInput.value.trim();
            if (taskText) {
                tasks.push({ text: taskText, completed: false });
                taskInput.value = '';
                saveTasks();
                renderTasks();
            }
        }

        function toggleTaskCompletion(index) {
            tasks[index].completed = !tasks[index].completed;
            saveTasks();
            renderTasks();
        }

        function deleteTask(index) {
            tasks.splice(index, 1);
            saveTasks();
            renderTasks();
        }

        function saveTasks() {
            localStorage.setItem('tasks', JSON.stringify(tasks));
        }

        addTaskButton.addEventListener('click', addTask);
        taskInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                addTask();
            }
        });

        renderTasks();
    </script>
</body>
</html>"}, "entry_point": "index.html", "how_to_run": "Open index.html in browser — no server needed"}

