<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Todo List</title>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="styles.css">
    <style>
        body { font-family: 'Inter', sans-serif; background-color: #f4f4f9; margin: 0; padding: 0; display: flex; justify-content: center; align-items: center; height: 100vh; }
        .container { background-color: #fff; padding: 20px; border-radius: 8px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.1); width: 300px; }
        h1 { font-weight: 600; text-align: center; }
        .task-input { display: flex; margin-bottom: 20px; }
        #taskInput { flex: 1; padding: 10px; border: 1px solid #ddd; border-radius: 4px; }
        #addTaskButton { padding: 10px; background-color: #007bff; color: #fff; border: none; border-radius: 4px; cursor: pointer; }
        #addTaskButton:hover { background-color: #0056b3; }
        .tasks { list-style: none; padding: 0; }
        .tasks li { padding: 10px; border: 1px solid #ddd; border-radius: 4px; margin-bottom: 10px; display: flex; justify-content: space-between; align-items: center; }
        .tasks li.completed { text-decoration: line-through; color: #888; }
        .tasks button { background-color: #dc3545; color: #fff; border: none; border-radius: 4px; cursor: pointer; padding: 5px 10px; }
        .tasks button:hover { background-color: #c82333; }
        .empty-state { text-align: center; color: #888; }
    </style>
</head>
<body>
    <div class="container">
        <h1>Todo List</h1>
        <div class="task-input">
            <input type="text" id="taskInput" placeholder="Add a new task">
            <button id="addTaskButton">Add</button>
        </div>
        <ul class="tasks" id="taskList"></ul>
        <div class="empty-state" id="emptyState">No tasks yet!</div>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            const taskInput = document.getElementById('taskInput');
            const addTaskButton = document.getElementById('addTaskButton');
            const taskList = document.getElementById('taskList');
            const emptyState = document.getElementById('emptyState');

            function loadTasks() {
                const tasks = JSON.parse(localStorage.getItem('tasks')) || [];
                tasks.forEach(task => {
                    createTaskElement(task.text, task.completed);
                });
                updateEmptyState();
            }

            function saveTasks() {
                const tasks = [];
                taskList.querySelectorAll('li').forEach(taskItem => {
                    tasks.push({
                        text: taskItem.querySelector('span').textContent,
                        completed: taskItem.classList.contains('completed')
                    });
                });
                localStorage.setItem('tasks', JSON.stringify(tasks));
            }

            function updateEmptyState() {
                if (taskList.children.length === 0) {
                    emptyState.style.display = 'block';
                } else {
                    emptyState.style.display = 'none';
                }
            }

            function createTaskElement(taskText, completed = false) {
                const taskItem = document.createElement('li');
                if (completed) {
                    taskItem.classList.add('completed');
                }

                const taskSpan = document.createElement('span');
                taskSpan.textContent = taskText;
                taskSpan.addEventListener('click', function() {
                    taskItem.classList.toggle('completed');
                    saveTasks();
                });

                const removeButton = document.createElement('button');
                removeButton.textContent = 'Remove';
                removeButton.addEventListener('click', function() {
                    taskList.removeChild(taskItem);
                    updateEmptyState();
                    saveTasks();
                });

                taskItem.appendChild(taskSpan);
                taskItem.appendChild(removeButton);
                taskList.appendChild(taskItem);
            }

            function addTask() {
                const taskText = taskInput.value.trim();
                if (taskText === '') {
                    alert('Please enter a task.');
                    return;
                }

                const existingTasks = Array.from(taskList.querySelectorAll('li span')).map(span => span.textContent);
                if (existingTasks.includes(taskText)) {
                    alert('Task already exists.');
                    return;
                }

                createTaskElement(taskText);
                taskInput.value = '';
                updateEmptyState();
                saveTasks();
            }

            addTaskButton.addEventListener('click', addTask);

            taskInput.addEventListener('keypress', function(event) {
                if (event.key === 'Enter') {
                    addTask();
                }
            });

            loadTasks();
        });
    </script>
</body>
</html>", "styles.css": ":root {
