{"project_type": "frontend_only", "files": {"index.html": "<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Tic Tac Toe</title>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&display=swap" rel="stylesheet">
    <style>
        :root {
            --primary-color: #4CAF50;
            --secondary-color: #f1f1f1;
            --accent-color: #FF5722;
            --font-color: #333;
            --gap-size: 10px;
        }
        body {
            font-family: 'Inter', sans-serif;
            background-color: var(--secondary-color);
            color: var(--font-color);
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
        }
        .container {
            max-width: 400px;
            width: 100%;
            padding: var(--gap-size);
            box-sizing: border-box;
            text-align: center;
        }
        h1 {
            margin-bottom: var(--gap-size);
        }
        .grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: var(--gap-size);
            margin-bottom: var(--gap-size);
        }
        .cell {
            background-color: #fff;
            border: 2px solid var(--primary-color);
            padding: 20px;
            font-size: 2rem;
            cursor: pointer;
            transition: background-color 0.3s ease;
        }
        .cell:hover {
            background-color: var(--primary-color);
            color: #fff;
        }
        .restart {
            background-color: var(--accent-color);
            color: #fff;
            border: none;
            padding: 10px 20px;
            font-size: 1rem;
            cursor: pointer;
            transition: background-color 0.3s ease;
        }
        .restart:hover {
            background-color: #e64a19;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Tic Tac Toe</h1>
        <div class="grid" id="grid">
            <div class="cell" data-index="0"></div>
            <div class="cell" data-index="1"></div>
            <div class="cell" data-index="2"></div>
            <div class="cell" data-index="3"></div>
            <div class="cell" data-index="4"></div>
            <div class="cell" data-index="5"></div>
            <div class="cell" data-index="6"></div>
            <div class="cell" data-index="7"></div>
            <div class="cell" data-index="8"></div>
        </div>
        <button class="restart" id="restart">Restart</button>
    </div>
    <script>
        const grid = document.getElementById('grid');
        const restartButton = document.getElementById('restart');
        let currentPlayer = 'X';
        let board = ['', '', '', '', '', '', '', '', ''];
        const winPatterns = [
            [0, 1, 2], [3, 4, 5], [6, 7, 8],
            [0, 3, 6], [1, 4, 7], [2, 5, 8],
            [0, 4, 8], [2, 4, 6]
        ];

        function checkWin() {
            return winPatterns.some(pattern => {
                const [a, b, c] = pattern;
                return board[a] && board[a] === board[b] && board[a] === board[c];
            });
        }

        function handleClick(event) {
            const cell = event.target;
            const index = cell.getAttribute('data-index');

            if (board[index] !== '' || checkWin()) return;

            board[index] = currentPlayer;
            cell.textContent = currentPlayer;

            if (checkWin()) {
                setTimeout(() => alert(`${currentPlayer} wins!`), 100);
            } else if (!board.includes('')) {
                setTimeout(() => alert('Draw!'), 100);
            } else {
                currentPlayer = currentPlayer === 'X' ? 'O' : 'X';
            }
        }

        function restartGame() {
            board = ['', '', '', '', '', '', '', '', ''];
            currentPlayer = 'X';
            document.querySelectorAll('.cell').forEach(cell => cell.textContent = '');
        }

        grid.addEventListener('click', handleClick);
        restartButton.addEventListener('click', restartGame);
    </script>
</body>
</html>"}, "entry_point": "index.html", "how_to_run": "Open index.html in browser — no server needed"}

