        async function deleteNote(id) {
            try {
                const response = await fetch(`/notes/${id}`, {
                    method: 'DELETE'
                });
                if (!response.ok) throw new Error('Failed to delete note');
                showSuccess('Note deleted successfully');
                fetchNotes();
            } catch (error) {
                showError(error.message);
            }
