    <title>Calculator</title>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&display=swap" rel="stylesheet">
    <style>
        :root {
            --primary-color: #4CAF50;
            --secondary-color: #f1f1f1;
            --button-color: #ffffff;
            --button-hover-color: #e0e0e0;
            --text-color: #333333;
            --font-family: 'Inter', sans-serif;
            --gap-size: 10px;
        }

        body {
            font-family: var(--font-family);
            background-color: var(--secondary-color);
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
        }

        .calculator {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: var(--gap-size);
            max-width: 400px;
            width: 100%;
            background-color: var(--primary-color);
            padding: var(--gap-size);
            border-radius: 8px;
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
        }

        .display {
            grid-column: span 4;
            background-color: var(--button-color);
            padding: 20px;
            font-size: 2em;
            text-align: right;
            border-radius: 4px;
            color: var(--text-color);
        }

        button {
            background-color: var(--button-color);
            border: none;
            padding: 20px;
            font-size: 1.5em;
            border-radius: 4px;
            cursor: pointer;
            transition: background-color 0.3s ease;
        }

        button:hover {
            background-color: var(--button-hover-color);
        }

        button:active {
            background-color: var(--primary-color);
            color: var(--button-color);
        }

        .operator {
            color: var(--primary-color);
        }
    </style>
</head>
<body>
    <div class="calculator">
        <div class="display" id="display">0</div>
        <button class="operator" onclick="clearDisplay()">C</button>
        <button class="operator" onclick="appendOperator('/')">/</button>
        <button class="operator" onclick="appendOperator('*')">*</button>
        <button class="operator" onclick="appendOperator('-')">-</button>
        <button onclick="appendNumber(7)">7</button>
        <button onclick="appendNumber(8)">8</button>
        <button onclick="appendNumber(9)">9</button>
        <button class="operator" onclick="appendOperator('+')">+</button>
        <button onclick="appendNumber(4)">4</button>
        <button onclick="appendNumber(5)">5</button>
        <button onclick="appendNumber(6)">6</button>
        <button onclick="calculate()">=</button>
        <button onclick="appendNumber(1)">1</button>
        <button onclick="appendNumber(2)">2</button>
        <button onclick="appendNumber(3)">3</button>
        <button onclick="appendNumber(0)">0</button>
        <button onclick="appendDecimal()">.</button>
    </div>

    <script>
        let displayValue = '0';
        let pendingOperator = null;
        let firstOperand = null;
        let waitingForSecondOperand = false;

        function updateDisplay() {
            const display = document.getElementById('display');
            display.textContent = displayValue;
        }

        function clearDisplay() {
            displayValue = '0';
            firstOperand = null;
            pendingOperator = null;
            waitingForSecondOperand = false;
            updateDisplay();
        }

        function appendNumber(number) {
            if (waitingForSecondOperand) {
                displayValue = number.toString();
                waitingForSecondOperand = false;
            } else {
                displayValue = displayValue === '0' ? number.toString() : displayValue + number;
            }
            updateDisplay();
        }

        function appendOperator(operator) {
            if (pendingOperator && waitingForSecondOperand) {
                pendingOperator = operator;
                return;
            }

            if (firstOperand === null) {
                firstOperand = parseFloat(displayValue);
            } else if (pendingOperator) {
                const result = calculateResult(firstOperand, parseFloat(displayValue), pendingOperator);
                displayValue = `${parseFloat(result.toFixed(7))}`;
