                const result = calculateResult(firstOperand, parseFloat(displayValue), pendingOperator);
                displayValue = result === 'Error' ? 'Error' : `${parseFloat(result.toFixed(7))}`;
                firstOperand = result;
                pendingOperator = null;
                waitingForSecondOperand = true;
                updateDisplay();
            }
        }

        // Performs the calculation based on the operator
        function calculateResult(first, second, operator) {
            switch (operator) {
                case '+':
                    return first + second;
                case '-':
                    return first - second;
                case '*':
                    return first * second;
                case '/':
                    return second !== 0 ? first / second : 'Error';
                default:
                    return second;
