                const result = performCalculation(pendingOperator, firstOperand, parseFloat(displayValue));
                displayValue = `${parseFloat(result.toFixed(7))}`;
                firstOperand = result;
            }
            pendingOperator = operator;
            waitingForSecondOperand = true;
            updateDisplay();
        }

        function appendDecimal() {
            if (!displayValue.includes('.')) {
                displayValue += '.';
            }
            updateDisplay();
        }

        function calculate() {
            if (pendingOperator && firstOperand !== null) {
                const result = performCalculation(pendingOperator, firstOperand, parseFloat(displayValue));
                displayValue = `${parseFloat(result.toFixed(7))}`;
                firstOperand = null;
                pendingOperator = null;
                waitingForSecondOperand = false;
                updateDisplay();
            }
        }

        function performCalculation(operator, firstOperand, secondOperand) {
            switch (operator) {
                case '+':
                    return firstOperand + secondOperand;
                case '-':
                    return firstOperand - secondOperand;
                case '*':
                    return firstOperand * secondOperand;
                case '/':
                    return secondOperand === 0 ? 'Error' : firstOperand / secondOperand;
                default:
                    return secondOperand;
            }
        }

        updateDisplay();
    </script>
</body>
