    <script>
        let currentOperand = '';
        let previousOperand = '';
        let operation = undefined;

        const displayElement = document.getElementById('display');

        // Clears the calculator display and resets operands and operation
        function clearDisplay() {
            currentOperand = '';
            previousOperand = '';
            operation = undefined;
            updateDisplay();
        }

        // Appends a number or decimal point to the current operand
        function appendNumber(number) {
            if (number === '.' && currentOperand.includes('.')) return; // Prevent multiple decimals
            currentOperand = currentOperand.toString() + number.toString();
            updateDisplay();
        }

        // Sets the operation and moves the current operand to the previous operand
        function chooseOperation(op) {
